// TestExecuteBead_ConcurrentWorkers_NoHEADRefRace is the regression test for
// concurrent `ddx work` against the same project hitting
// "fatal: cannot lock ref 'HEAD': is at X but expected Y" CAS failures during
// the pre-execute-bead checkpoint.
//
// Before the fix, Run() called CommitTracker (locked) → SynthesizeCommit
// (unlocked) → resolveBase (unlocked) → WorktreeAdd (unlocked). When two
// workers raced, worker B's CommitTracker advanced HEAD between worker A's
// `git add` and `git commit` inside SynthesizeCommit, and A's commit failed
// the HEAD compare-and-swap.
//
// After the fix, the entire pre-dispatch sequence runs inside one
// withTrackerLock acquisition, so concurrent workers serialize through it.
func TestExecuteBead_ConcurrentWorkers_NoHEADRefRace(t *testing.T) {
	const n = 5
	projectRoot, _ := newScriptHarnessRepo(t, n)

	// Each goroutine gets its own directive file (no-op directive — we don't
	// care about the agent's output, only about the parent-repo
	// pre-dispatch sequence racing).
	dirFiles := make([]string, n)
	tmp := t.TempDir()
	for i := 0; i < n; i++ {
		dirFile := filepath.Join(tmp, fmt.Sprintf("directive-%d.txt", i+1))
		writeDirectiveFile(t, dirFile, []string{})
		dirFiles[i] = dirFile
	}

	// Build runners up front so worker goroutines do not share construction-time
	// setup.
	runners := make([]AgentRunner, n)
	rcfgs := make([]config.ResolvedConfig, n)
	for i := 0; i < n; i++ {
		runners[i] = NewRunner(Config{})
		rcfgs[i] = config.NewTestConfigForBead(config.TestBeadConfigOpts{
			Harness: "script",
			Model:   dirFiles[i],
		}).Resolve(config.CLIOverrides{})
	}

	// Seed caller dirt in the parent so each goroutine's SynthesizeCommit
	// has real work to do — exercises the `git add` / `git commit` race
	// window inside the locked critical section.
	require.NoError(t, os.WriteFile(filepath.Join(projectRoot, "caller-dirt.txt"),
		[]byte("dirt\n"), 0o644))

	// Run n ExecuteBeadWithConfig calls concurrently against the SAME
	// projectRoot, with NO outer mutex serialising them. Without the
	// pre-dispatch lock-scope fix, this races on HEAD.
	var wg sync.WaitGroup
	results := make([]*ExecuteBeadResult, n)
	errs := make([]error, n)
	gitOps := &RealGitOps{}
	for i := 0; i < n; i++ {
		i := i
		wg.Add(1)
		go func() {
			defer wg.Done()
			beadID := fmt.Sprintf("ddx-int-%04d", i+1)
			results[i], errs[i] = ExecuteBeadWithConfig(
				context.Background(),
				projectRoot,
				beadID,
				rcfgs[i],
				ExecuteBeadRuntime{AgentRunner: runners[i]},
				gitOps,
			)
		}()
	}
	wg.Wait()

	// Primary regression assertion: no goroutine surfaced the
	// compare-and-swap error. Any "cannot lock ref" / "but expected"
	// failure means the race re-opened.
	for i, e := range errs {
		if e != nil {
			msg := e.Error()
			if IsGitUpdateRefCompareAndSwapFailure(msg) {
				t.Fatalf("worker %d hit HEAD CAS race (regression): %v", i, e)
			}
			require.NoErrorf(t, e, "worker %d returned unexpected error: %v", i, e)
		}
	}

	// Each goroutine must have produced a result with a baseRev resolved
	// from the locked sequence. The exact run outcome is not asserted here —
	// the script harness with an empty directive yields no_changes, which is
	// a successful pre-dispatch (we got past the worktree creation).
	seenBaseRevs := map[string]bool{}
	for i, r := range results {
		require.NotNilf(t, r, "worker %d nil result", i)
		assert.NotEmptyf(t, r.BaseRev, "worker %d BaseRev empty", i)
		seenBaseRevs[r.BaseRev] = true
	}

	// All n attempts ran serially through the lock — at least one tracker
	// commit and one checkpoint commit advanced main per first-acquirer.
	// Subsequent acquirers either no-op'd (dirt already committed) or
	// committed fresh dirt. Either way, the parent's HEAD is consistent
	// (only one writer at a time) and at least one commit landed beyond
	// the seed.
	commitCount := gitCommitCount(t, projectRoot, "HEAD")
	assert.GreaterOrEqualf(t, commitCount, 3,
		"main must have advanced past initial seed + bead seed (got %d commits)",

	return true, nil
}

// checkpointPreDispatchDirt captures DDx bookkeeping changes as a commit on
// the current branch without using the caller checkout's real index or commit
// hooks. The checkpoint is intentionally narrow: if the parent checkout also
// contains ordinary implementation files, the attempt fails with an actionable
// error so those changes can be committed in the bead's substantive
// [ddx-<id>] commit instead of being folded into the checkpoint.
func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
	if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
		return false, nil
	}
	headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").Output()
	if err != nil {
		return false, nil
	}
	head := strings.TrimSpace(string(headOut))
	if head == "" {
		return false, nil
	}

	dirtyPaths, err := preDispatchCheckpointDirtyPaths(projectRoot)
	if err != nil {
		return false, err
	}
	if len(dirtyPaths) == 0 {
		return false, nil
	}

	allowedPaths := make([]string, 0, len(dirtyPaths))
	blockedPaths := make([]string, 0)
	for _, path := range dirtyPaths {
		if preDispatchCheckpointAllowedPath(path) {
			allowedPaths = append(allowedPaths, path)
			continue
		}
		blockedPaths = append(blockedPaths, path)
	}
	sort.Strings(allowedPaths)
	sort.Strings(blockedPaths)
	if len(blockedPaths) > 0 {
		return false, fmt.Errorf(
			"checkpoint refused to absorb implementation changes outside DDx bookkeeping: %s; commit those files in the bead's [ddx-<id>] substantive commit before rerunning",
			strings.Join(blockedPaths, ", "),
		)
	}
	if len(allowedPaths) == 0 {
		return false, nil
	}

	indexFile, err := os.CreateTemp("", "ddx-pre-dispatch-index-*")
	if err != nil {
		return false, fmt.Errorf("creating temp checkpoint index: %w", err)
	}
	indexPath := indexFile.Name()
	_ = indexFile.Close()
	_ = os.Remove(indexPath)
	defer func() { _ = os.Remove(indexPath) }()

	gitWithIndex := func(args ...string) ([]byte, error) {
		cmd := internalgit.Command(context.Background(), projectRoot, args...)
		cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
		return cmd.CombinedOutput()
	}

	if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
		return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
	}

	addArgs := []string{"add", "-A", "--force", "--"}
	addArgs = append(addArgs, allowedPaths...)
	if out, err := gitWithIndex(addArgs...); err != nil {
		return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
	}

	changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
	if err != nil {
		return false, fmt.Errorf("checking checkpoint diff: %w", err)
	}
	if len(bytes.TrimSpace(changedOut)) == 0 {
		return false, nil
	}

	treeOut, err := gitWithIndex("write-tree")
	if err != nil {
		return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
	}
	tree := strings.TrimSpace(string(treeOut))
	msg := "chore: checkpoint pre-execute-bead " + attemptID
	commitOut, err := internalgit.Command(context.Background(), projectRoot,
		"-c", "user.name=ddx-checkpoint",
		"-c", "user.email=checkpoint@ddx.local",
		"commit-tree", tree, "-p", head, "-m", msg,
	).CombinedOutput()
	if err != nil {
		return false, fmt.Errorf("creating checkpoint commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
	}
	commit := strings.TrimSpace(string(commitOut))

	refOut, _ := internalgit.Command(context.Background(), projectRoot, "symbolic-ref", "-q", "HEAD").Output()
	ref := strings.TrimSpace(string(refOut))
	if ref == "" {
		ref = "HEAD"
	}
	if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", ref, commit, head).CombinedOutput(); err != nil {
		return false, fmt.Errorf("advancing checkpoint ref: %s: %w", strings.TrimSpace(string(out)), err)
	}
	if out, err := internalgit.Command(context.Background(), projectRoot, "read-tree", "HEAD").CombinedOutput(); err != nil {
		return false, fmt.Errorf("syncing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return true, nil
}

func preDispatchCheckpointDirtyPaths(projectRoot string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), projectRoot,
		"status", "--porcelain=v1", "-z", "--untracked-files=all", "--ignored=matching", "--", ".").Output()
	if err != nil {
		return nil, fmt.Errorf("listing checkpoint dirt: %w", err)
	}
	if len(out) == 0 {
		return nil, nil
	}

	seen := make(map[string]bool)
	paths := make([]string, 0, 8)
	for len(out) > 0 {
		recordEnd := bytes.IndexByte(out, 0)
		if recordEnd == -1 {
			recordEnd = len(out)
		}
		record := out[:recordEnd]
		if recordEnd < len(out) {
			out = out[recordEnd+1:]
		} else {
			out = nil
		}
		if len(record) < 3 {
			continue
		}
		path := filepath.ToSlash(string(record[3:]))
		if path != "" && !seen[path] {
			seen[path] = true
			paths = append(paths, path)
		}
		if record[0] == 'R' || record[0] == 'C' {
			recordEnd = bytes.IndexByte(out, 0)
			if recordEnd == -1 {
				recordEnd = len(out)
			}
			record = out[:recordEnd]
			if recordEnd < len(out) {
				out = out[recordEnd+1:]
			} else {
				out = nil
			}
			path := filepath.ToSlash(string(record))
			if path != "" && !seen[path] {
				seen[path] = true
				paths = append(paths, path)
			}
		}
	}
	return paths, nil
}

func preDispatchCheckpointAllowedPath(path string) bool {
	switch {
	case path == ".ddx/beads.jsonl":
		return true
	case strings.HasPrefix(path, ".ddx/executions/"):
		return true
	case strings.HasPrefix(path, ".ddx/runs/"):
		return true
	case strings.HasPrefix(path, ".ddx/run-state/"):
		return true
	case path == ".ddx/run-state.json":
		return true
	case path == ExecutionCleanupMetadataFileName:
		return true
	default:
		return false
	}
}

